const SUBTABS = [
  { id: "create-journal",  icon: "📰", label: "Create Journal",    n: "04" },
  { id: "submit-journal",  icon: "⛓",  label: "Submit to Journal", n: "05" },
  { id: "review",          icon: "🧪", label: "Peer Review",       n: "06" },
  { id: "reward",          icon: "🏆", label: "Reward Reviewer",   n: "07" },
];

